#include <iostream>
#include <vector>
#include <algorithm>
using namespace std;
class Solution {
public:
    void buildMaxHeap(vector<int>& nums) {
        int n = nums.size();
        for (int i = n / 2 - 1; i >= 0; i--) {
            int largest = i;
            int left = 2 * i + 1;
            int right = 2 * i + 2;
            if (left < n && nums[left] > nums[largest])
                largest = left;
            if (right < n && nums[right] > nums[largest])
                largest = right;
            if (largest != i) {
                swap(nums[i], nums[largest]);
                buildMaxHeap(nums);
            }
        }
    }
};

int main() {
    Solution s;
    vector<int> nums = {1, 3, 5, 7, 9};
    cout << *nums.begin();
    for (auto n : nums)
        cout << ' ' << n;
    cout << endl;

    s.buildMaxHeap(nums);
    cout << *nums.begin();
    for (auto n : nums)
        cout << ' ' << n;
    cout << endl;

    return 0;
}
